UPDATE public.questions SET
  stimulus_text = 'In her essay on urban soundscapes, writer 3 contends that city planners should classify chronic noise pollution as a public-health hazard, citing longitudinal studies linking traffic noise to elevated cortisol, fragmented sleep, and diminished cognitive performance among residents. She describes neighborhoods where sirens, construction, and highway hum overlap for eighteen hours daily, leaving inhabitants with interrupted rest even when particulate counts meet regulatory thresholds. Community interviews quoted in the essay repeatedly mention difficulty concentrating at work, heightened irritability at home, and reluctance to open windows despite heat. The writer contrasts cosmetic beautification projects—planters, murals, and repainted facades—with measurable acoustic interventions such as berms, low-noise pavement, delivery-time restrictions, and targeted speed reductions. She acknowledges that absolute silence is unattainable in dense cities, yet insists that reducing predictable high-decibel spikes could yield health benefits comparable to modest gains in accessible green space. The essay concludes that sound belongs in municipal planning budgets alongside air quality and light pollution.',
  question_text = 'Which choice represents the most defensible inference the reader can draw from the passage?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The researchers suppressed unfavorable results because the findings contradicted their initial hypothesis about reef dynamics.","is_correct":false,"explanation":"The passage reports published findings and follow-up transects; it does not suggest deliberate suppression of data."},{"id":"B","text":"Every participant in sleep-related studies universally fails to recall word lists when deprived of rest for any duration.","is_correct":false,"explanation":"Too absolute; the passage compares groups under controlled conditions rather than claiming universal failure across all contexts."},{"id":"C","text":"The principle illustrated in the passage may apply beyond the specific case study, though the authors acknowledge methodological limits.","is_correct":true,"explanation":"When a study isolates a variable and documents a pattern with stated cautions, readers may infer broader applicability without treating the study as unlimited proof."},{"id":"D","text":"The passage provides exact retail pricing for every consumer product mentioned in interviews with shop owners.","is_correct":false,"explanation":"No pricing data appears; the passage focuses on procurement flexibility and organizational structure during disruption."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The passage presents a specific finding with explicit limitations yet still implies a principle extending beyond the immediate example. The passage anchors the correct choice in language such as "In her essay on urban soundscapes, writer 3 contends that city planners should classify chronic nois…", which eliminates options that contradict or overreach that evidence. Choice C is correct because it aligns with the textual logic: . Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
