UPDATE public.questions SET
  stimulus_text = 'The initial randomized trial failed to detect a statistically reliable effect despite adequate sample size and pre-registered analysis plans. ______ the replication study, which enrolled additional participants and extended the observation window by six months, revealed a robust pattern consistent with the researchers'' preregistered hypothesis.',
  question_text = 'Which choice completes the text with the most logical transition?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"Complicating the binary the author has established,","is_correct":true,"explanation":"Complicating the binary the author has established, This participial phrase matches the rhetorical relationship between the two clauses: it signals contrast while preserving sentence grammar. Hard Digital SAT transition items expect syntactic embedding rather than a bare adverb. The following clause must read as a grammatically complete continuation."},{"id":"B","text":"Undermining the neat separation outlined above,","is_correct":false,"explanation":"Undermining the neat separation outlined above, This phrase suggests contrast, which misaligns with how the prior and following clauses relate. Hard transition items punish single-word pivots when the logic requires a fuller rhetorical bridge between contrasting trial outcomes."},{"id":"C","text":"Drawing the logical consequence from the evidence just presented,","is_correct":false,"explanation":"Drawing the logical consequence from the evidence just presented, This phrase suggests contrast, which misaligns with how the prior and following clauses relate. Hard transition items punish single-word pivots when the logic requires a fuller rhetorical bridge between contrasting trial outcomes."},{"id":"D","text":"Translating the prior observation into a broader principle,","is_correct":false,"explanation":"Translating the prior observation into a broader principle, This phrase suggests contrast, which misaligns with how the prior and following clauses relate. Hard transition items punish single-word pivots when the logic requires a fuller rhetorical bridge between contrasting trial outcomes."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The two clauses contrast a null initial trial with a successful replication. Hard transition items require a participial or clausal bridge—not a single adverb—that signals contrast while grammatically modifying the subject of the following clause. The passage anchors the correct choice in language such as "The initial randomized trial failed to detect a statistically reliable effect despite adequate sampl…", which eliminates options that contradict or overreach that evidence. Choice A is correct because it aligns with the textual logic: Complicating the binary the author has established,. Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
