UPDATE public.questions SET
  stimulus_text = 'Economists analyzing market disruption 4 observed that independent retailers adapted more nimbly than national chains when supply chains stalled, partly because they could reorder from local wholesalers within days rather than awaiting centralized distribution. While big-box stores waited for corporate approval to alter procurement contracts, corner shops consulted handwritten contact lists and shifted product mix toward shelf-stable goods and services independent of overseas shipping. The economists interviewed owners who renegotiated credit terms with regional suppliers and temporarily expanded delivery radius to retain customers. National chains, bound to uniform pricing algorithms and national vendor agreements, could not pivot without multi-week executive review cycles. The study does not claim small stores universally outperform conglomerates; rather, it demonstrates that organizational flexibility and embedded local relationships became decisive when long-distance logistics failed abruptly. Readers should infer that scale economies can become liabilities during sudden disruptions that reward improvisation over standardized efficiency.',
  question_text = 'Which choice most accurately describes the rhetorical structure of the passage as a whole?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The passage is organized to explain a multi-step cause-and-effect relationship supported by longitudinal field evidence.","is_correct":true,"explanation":"The passage develops an explanatory arc consistent with to explain a multi-step cause-and-effect relationship supported by longitudinal field evidence, introducing context and then supporting evidence."},{"id":"B","text":"The passage presents a random sequence of unrelated facts without thematic connection between successive paragraphs.","is_correct":false,"explanation":"The passage connects ideas across paragraphs through repeated causal language; it is not a disconnected list."},{"id":"C","text":"The passage primarily argues that scientific research should be abandoned because laboratory findings never generalize.","is_correct":false,"explanation":"The passage presents research findings and field surveys rather than rejecting scientific inquiry."},{"id":"D","text":"The passage provides a chronological biography of a single individual from childhood through retirement.","is_correct":false,"explanation":"No single biography structures the passage; multiple actors, sites, and studies appear instead."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage is organized to explain a multi-step cause-and-effect relationship supported by longitudinal field evidence, moving from context through evidence to implication. The passage anchors the correct choice in language such as "Economists analyzing market disruption 4 observed that independent retailers adapted more nimbly tha…", which eliminates options that contradict or overreach that evidence. Choice A is correct because it aligns with the textual logic: x. Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
