UPDATE public.questions SET
  stimulus_text = 'Educators reviewing literacy intervention 8 concluded that students who engaged in structured pair discussion improved comprehension scores more than peers who completed silent worksheets covering identical texts. Teachers in discussion classrooms reported that students cited textual evidence when disagreeing—a behavior rarely observed during worksheet completion even when prompts requested quotations. Standardized pre- and post-tests showed a twelve-point average gain for the discussion cohort versus a four-point gain for the worksheet cohort over the same six-week unit on informational nonfiction. The educators emphasize that discussion prompts were scripted rather than unstructured chat: each partner had to cite a line, paraphrase a counterargument, and reconcile conflicting interpretations before moving on. They argue that collaborative talk externalizes comprehension strategies weaker readers otherwise keep invisible, making metacognitive moves available for teacher feedback. The passage supports structured peer dialogue as an instructional lever complementary to, rather than substituting for, independent silent reading.',
  question_text = 'According to the passage, which statement is most strongly supported by the text?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The passage establishes that coral recruitment fell sharply at sites where herbivore biomass declined, linking herbivory to measurable recruitment outcomes across monitored sites.","is_correct":true,"explanation":"The passage explicitly ties coral recruitment fell sharply at sites where herbivore biomass declined to reef health through comparative site data rather than speculative claims."},{"id":"B","text":"Once macroalgae dominate a reef, coral larvae can never attach to any surface regardless of subsequent grazing pressure.","is_correct":false,"explanation":"The passage describes recovery mechanisms and does not claim permanent loss once algae appear; grazing can restore bare rock."},{"id":"C","text":"The authors dismiss empirical field surveys in favor of anecdotal reports from recreational divers who visit the sites.","is_correct":false,"explanation":"The passage cites transects, chemical assays, and follow-up surveys—methods inconsistent with rejecting scientific inquiry."},{"id":"D","text":"Temperature and salinity fluctuations alone explain every decline in coral recruitment documented in the longitudinal study.","is_correct":false,"explanation":"The passage states recruitment declined even when temperature and salinity remained stable, implicating grazing rather than water chemistry alone."}]'::jsonb,
