  correct_answer = 'B',
  explanation = 'Context shows the team''s first conclusion required replication after further trials; "perfunctory" must fit a meaning of provisional or unsettled judgment. The passage anchors the correct choice in language such as "Historians reconstructing trade route 2 emphasize that camel caravans transported not only commoditi…", which eliminates options that contradict or overreach that evidence. Choice B is correct because it aligns with the textual logic: carried out with minimal effort or interest. Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
  difficulty = 'hard',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_template_v1","explanation_v2":true,"english_content_v2":true,"difficulty_reclassified_at":"2026-06-12T20:24:49.070Z","difficulty_reclassified_to":"medium","english_content_upgraded_at":"2026-06-12T20:01:56.880Z","difficulty_reclassified_from":"hard","difficulty_reclassified_reason":"calibration_shift_down_v1","english_content_upgrade_method":"upgrade-english-content.mjs","hard_content_v2":true,"hard_content_upgraded_at":"2026-06-12T20:29:31.380Z","hard_content_upgrade_method":"generate-hard-english.mjs","prior_difficulty":"medium"}'::jsonb,
